const agents = $input.all().map(i => i.json);

const ALERT_THRESHOLDS = {
  min_conversion_rate: 10,        // below 10% is concerning
  max_overdue_followups: 5,       // more than 5 overdue is bad
  min_weekly_new_leads: 3,        // fewer than 3 new leads/week is low
  performance_colors: {
    excellent: { min: 20, color: '#27ae60', emoji: 'star' },
    good:      { min: 15, color: '#2ecc71', emoji: 'thumbsup' },
    average:   { min: 10, color: '#f39c12', emoji: 'neutral_face' },
    poor:      { min: 0,  color: '#e74c3c', emoji: 'warning' }
  }
};

const getPerformanceTier = (rate) => {
  if (rate >= 20) return 'excellent';
  if (rate >= 15) return 'good';
  if (rate >= 10) return 'average';
  return 'poor';
};

const agentsNeedingAttention = agents.filter(a => 
  a.conversion_rate_pct < ALERT_THRESHOLDS.min_conversion_rate ||
  a.overdue_followups > ALERT_THRESHOLDS.max_overdue_followups
);

// Sort agents for leaderboard
const sortedAgents = [...agents].sort((a, b) => b.conversion_rate_pct - a.conversion_rate_pct);

const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: 'Agent Performance Report - Week Ending ' + new Date().toLocaleDateString('en-ZA') }
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Team Overview:* ${agents.length} active agents | ${agents.reduce((s,a) => s + Number(a.total_leads), 0)} total leads | ${agents.reduce((s,a) => s + Number(a.converted_leads), 0)} conversions` }
  },
  { type: 'divider' },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: '*Leaderboard*' }
  },
  ...sortedAgents.slice(0, 5).map((agent, idx) => {
    const tier = getPerformanceTier(agent.conversion_rate_pct);
    const medal = idx === 0 ? ':first_place_medal:' : idx === 1 ? ':second_place_medal:' : idx === 2 ? ':third_place_medal:' : `${idx + 1}.`;
    return {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `${medal} *${agent.agent_name}*\n` +
              `Conversion: ${agent.conversion_rate_pct}% | Leads: ${agent.total_leads} | Converted: ${agent.converted_leads}\n` +
              `New This Week: ${agent.new_leads_this_week} | Overdue: ${agent.overdue_followups}`
      }
    };
  })
];

if (agentsNeedingAttention.length > 0) {
  slackBlocks.push({ type: 'divider' });
  slackBlocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: ':warning: *Agents Needing Attention*' }
  });
  agentsNeedingAttention.forEach(agent => {
    const issues = [];
    if (agent.conversion_rate_pct < ALERT_THRESHOLDS.min_conversion_rate) {
      issues.push(`Low conversion rate (${agent.conversion_rate_pct}%)`);
    }
    if (agent.overdue_followups > ALERT_THRESHOLDS.max_overdue_followups) {
      issues.push(`${agent.overdue_followups} overdue follow-ups`);
    }
    slackBlocks.push({
      type: 'section',
      text: { type: 'mrkdwn', text: `*${agent.agent_name}*: ${issues.join(', ')}` }
    });
  });
}

return [{
  json: {
    agents,
    sorted_agents: sortedAgents,
    agents_needing_attention: agentsNeedingAttention,
    slack_blocks: JSON.stringify(slackBlocks),
    report_date: new Date().toLocaleDateString('en-ZA'),
    total_leads: agents.reduce((s,a) => s + Number(a.total_leads), 0),
    total_conversions: agents.reduce((s,a) => s + Number(a.converted_leads), 0),
    team_conversion_rate: agents.length > 0 ?
      (agents.reduce((s,a) => s + Number(a.converted_leads), 0) / 
       agents.reduce((s,a) => s + Number(a.total_leads), 1) * 100).toFixed(1) : 0
  }
}];

const data = $('Analyze Performance').first().json;
const agentsToAlert = data.agents_needing_attention;

if (agentsToAlert.length === 0) return [];

// Return one item per agent needing attention
return agentsToAlert.map(agent => ({
  json: {
    ...agent,
    manager_email: process.env.MANAGER_EMAIL || 'manager@puraestate.co.za'
  }
}));
